import psycopg2

def connect():
    connection = psycopg2.connect(
        host="your_host",
        database="your_database",
        user="your_user",
        password="your_password"
    )
    return connection

def search_users(username=None, email=None, role=None, status=None, connection=None):
    query = """
        SELECT * FROM users WHERE 1=1
    """

    if username:
        query += " AND username = %s"

    if email:
        query += " AND email = %s"

    if role:
        query += " AND role = %s"

    if status:
        query += " AND status = %s"

    cur = connection.cursor()
    cur.execute(query, (username, email, role, status))
    results = cur.fetchall()
    return results

